"use strict";(()=>{document.addEventListener("DOMContentLoaded",()=>{let n=document.getElementById("provider"),s=document.getElementById("apiKey"),a=document.getElementById("model"),o=document.getElementById("persona"),l=document.getElementById("saveBtn"),t=document.getElementById("status");chrome.storage.sync.get(["provider","apiKey","model","persona"],e=>{n.value=e.provider||"gemini",s.value=e.apiKey||"",a.value=e.model||"",o.value=e.persona||""}),l.addEventListener("click",()=>{let e=n.value,c=s.value.trim(),d=a.value.trim(),m=o.value.trim();chrome.storage.sync.set({provider:e,apiKey:c,model:d,persona:m},()=>{t.textContent="Settings saved successfully!",t.className="status success",setTimeout(()=>{t.style.display="none",t.className="status"},3e3)})})});})();
